class SelfHealingGenerator:
    def __init__(self, analyzer, verifier, patching_engine):
        self.analyzer = analyzer
        self.verifier = verifier
        self.patching_engine = patching_engine

    def generate_patch(self, vulnerabilities: list, code: str) -> str:
        """Generate patches for detected vulnerabilities"""
        patch_plan = self.verifier.generate_patch_plan(vulnerabilities)
        patches = []

        for vuln in vulnerabilities:
            patch = self.patching_engine.generate(vuln, code)
            patches.append(patch)

        return self.apply_patches(code, patches)

    def apply_patches(self, code: str, patches: list) -> str:
        """Safely apply patches to code"""
        patched = code
        for patch in patches:
            patched = self.patching_engine.apply(patched, patch)
        return patched
